			&lt;td colspan=&quot;2&quot; style=&quot;width:179px;&quot;&gt;
			&lt;p align=&quot;center&quot;&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Column-B (Continent)&lt;/span&gt;&lt;/p&gt;
