			&lt;p align=&quot;center&quot;&gt;a.&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:151px;&quot;&gt;
			&lt;p style=&quot;margin-left:7.05pt;&quot;&gt;North America&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:28px;&quot;&gt;
			&lt;p align=&quot;center&quot;&gt;ii.&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:123px;&quot;&gt;
			&lt;p style=&quot;margin-left:6.95pt;&quot;&gt;Lake Superior&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:28px;&quot;&gt;
			&lt;p align=&quot;center&quot;&gt;b.&lt;/p&gt;
